class Speaker:
    def __init__(self, id, name, email):
        self.id = id
        self.name = name
        self.email = email

def get_speaker(speaker_id):
    query = "SELECT * FROM speakers WHERE id = '%s'" % speaker_id
    with connection.cursor() as cursor:
        cursor.execute(query)
        row = cursor.fetchone()
        return Speaker(row[0], row[1], row[2])

